parameters.jsCode:
const storyboard = $('Parse JSON IA').item.json;
const batchResult = $input.item.json;
const originalData = $('Webhook Trigger').first().json.body;

for (let i = 0; i < storyboard.scenes.length; i++) {
    storyboard.scenes[i].media_filename = "NICHE";
    storyboard.scenes[i].subtitle_pos   = 5; // center
    storyboard.scenes[i].subtitle_size  = 48;
}

return {
  title:     storyboard.title,
  scenes:    storyboard.scenes,
  niche:     originalData.niche || "general",
  voice_id:  originalData.voice_id || "es-ES-AlvaroNeural",
  tts_engine: "edge-tts",
  tts_speed:  1.1,
  batch_id:   batchResult.batch_id
};
